SELECT
    id, user_id, topic_id, filename, oss_url, storage_type, file_size, is_public, audit_status, upload_time
FROM biz_image

    audit_status != 4
    AND user_id = #{userId}
    AND topic_id = #{topicId}

        AND filename LIKE CONCAT(#{filename}, '%')

    AND storage_type = #{storageType}
    AND is_public = #{isPublic}
    AND audit_status = #{auditStatus}

ORDER BY upload_time DESC

SELECT i.id AS imageId, i.filename, COUNT(m.id) AS refCount FROM biz_image i LEFT JOIN biz_note_image_mapping m ON i.id = m.image_id AND m.is_deleted = 0 WHERE i.audit_status != 4 AND i.id IN
#{id}
GROUP BY i.id

